// ── HELPERS ────────────────────────────────────────────────────────────────────
function pc(p) {
  if (p >= 90) return '#C89B3C';
  if (p >= 75) return '#b8863a';
  if (p >= 58) return '#7a6035';
  if (p >= 42) return '#5C677D';
  if (p >= 25) return '#3a6ea8';
  return '#2a5080';
}

function calcPct(vals, v, lowerBetter) {
  const sorted = [...vals].sort((a, b) => a - b);
  const b = sorted.filter(x => x < v).length;
  const e = sorted.filter(x => x === v).length;
  const raw = sorted.length ? Math.round(((b + e * 0.5) / sorted.length) * 100) : 50;
  return lowerBetter ? 100 - raw : raw;
}

function normalizeGrade(value) {
  const raw = String(value || '').trim().toLowerCase();
  return GRADE_VALUES.find(g => g.toLowerCase() === raw) || '';
}

function isPositionText(value) {
  const raw = String(value || '').trim();
  if (!raw) return false;
  return /^[A-Z0-9,\s/.-]+$/.test(raw) && /[A-Z]/.test(raw);
}

function normalizePlayerIdentity(p) {
  if (!p) return;

  p.name = String(p.name || '')
    .replace(/\s+(?:#|\/)\d+\s*$/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  const trailingGrade = p.name.match(/\s+(Freshman|Sophomore|Junior|Senior)$/i);
  if (trailingGrade) {
    const grade = normalizeGrade(trailingGrade[1]);
    p.name = p.name.slice(0, trailingGrade.index).trim();
    if (!normalizeGrade(p.year)) {
      if (isPositionText(p.year) && !p.pos) p.pos = p.year;
      p.year = grade;
    }
  }

  const normalizedYear = normalizeGrade(p.year);
  if (normalizedYear) p.year = normalizedYear;
}

function normalizePlayers() {
  AP.forEach(normalizePlayerIdentity);
  PP.forEach(normalizePlayerIdentity);
}

function setupPlayerScore() {
  HSC.PS = { label:'PS', fmt: v => v.toFixed(1) };
  PSC.PS = { label:'PS', fmt: v => v.toFixed(1), lowerBetter:false };

  const replaceStat = (arr, from, to) => {
    const idx = arr.indexOf(from);
    if (idx >= 0) arr.splice(idx, 1, to);
  };
  const removeStat = (arr, stat) => {
    const idx = arr.indexOf(stat);
    if (idx >= 0) arr.splice(idx, 1);
  };
  replaceStat(HIT_TABLE_COLS, 'OFF', 'PS');
  replaceStat(PIT_TABLE_COLS, 'WAR', 'PS');
  HIT_PCT_GROUPS.forEach(g => removeStat(g.stats, 'OFF'));
  PIT_PCT_GROUPS.forEach(g => removeStat(g.stats, 'WAR'));

  const hitQualified = AP.filter(p => p.qualified);
  const pitQualified = PP.filter(p => p.qualPitch);
  const hitVals = stat => hitQualified.map(p => p[stat]).filter(Number.isFinite);
  const pitVals = stat => pitQualified.map(p => p[stat]).filter(Number.isFinite);

  const h = {
    wRC_plus: hitVals('wRC_plus'),
    wOBA: hitVals('wOBA'),
    OPS: hitVals('OPS'),
    ISO: hitVals('ISO'),
    BB_pct: hitVals('BB_pct'),
    BsR: hitVals('BsR'),
  };
  if (!TEAM_POWER_RATINGS.length) calculateTeamPowerRatings();
  AP.forEach(p => {
    p.PS_base =
      calcPct(h.wRC_plus, p.wRC_plus, false) * 0.45 +
      calcPct(h.wOBA, p.wOBA, false) * 0.20 +
      calcPct(h.OPS, p.OPS, false) * 0.15 +
      calcPct(h.ISO, p.ISO, false) * 0.10 +
      calcPct(h.BB_pct, p.BB_pct, false) * 0.05 +
      calcPct(h.BsR, p.BsR, false) * 0.05;
    p.PS_sos = playerSOSAdjustment(p.team);
    p.PS = clamp(p.PS_base + p.PS_sos);
  });

  const q = {
    ERA_minus: pitVals('ERA_minus'),
    FIP_minus: pitVals('FIP_minus'),
    WHIP: pitVals('WHIP'),
    K7: pitVals('K7'),
    KBB: pitVals('KBB'),
    IP: pitVals('IP'),
  };
  PP.forEach(p => {
    p.PS_base =
      calcPct(q.ERA_minus, p.ERA_minus, true) * 0.30 +
      calcPct(q.FIP_minus, p.FIP_minus, true) * 0.25 +
      calcPct(q.WHIP, p.WHIP, true) * 0.15 +
      calcPct(q.K7, p.K7, false) * 0.15 +
      calcPct(q.KBB, p.KBB, false) * 0.10 +
      calcPct(q.IP, p.IP, false) * 0.05;
    p.PS_sos = playerSOSAdjustment(p.team);
    p.PS = clamp(p.PS_base + p.PS_sos);
  });
}

function playerSOSAdjustment(team) {
  if (!TEAM_POWER_RATINGS.length) calculateTeamPowerRatings();
  const power = TEAM_POWER_BY_TEAM[team];
  if (!power || !Number.isFinite(power.sosComp)) return 0;
  return clamp((power.sosComp - 50) * 0.10, -5, 5);
}

function resetHitPage() { hitPage = 1; renderHitTable(); }
function resetPitPage() { pitPage = 1; renderPitchTable(); }

function setLeaderPage(kind, page) {
  if (kind === 'hit') {
    hitPage = page;
    renderHitTable();
  } else {
    pitPage = page;
    renderPitchTable();
  }
}

function renderPagination(kind, total, page, pageSize) {
  const el = document.getElementById(kind === 'hit' ? 'hitPagination' : 'pitPagination');
  if (!el) return;
  if (!total) {
    el.innerHTML = '';
    return;
  }

  const pages = Math.max(1, Math.ceil(total / pageSize));
  const start = (page - 1) * pageSize + 1;
  const end = Math.min(total, page * pageSize);
  el.innerHTML = `
    <div class="pagination-info">Showing <span>${start}-${end}</span> of <span>${total}</span></div>
    <div class="pagination-actions">
      <button class="pagination-btn" onclick="setLeaderPage('${kind}', 1)" ${page <= 1 ? 'disabled' : ''}>First</button>
      <button class="pagination-btn" onclick="setLeaderPage('${kind}', ${page - 1})" ${page <= 1 ? 'disabled' : ''}>Previous</button>
      <span>Page ${page} of ${pages}</span>
      <button class="pagination-btn" onclick="setLeaderPage('${kind}', ${page + 1})" ${page >= pages ? 'disabled' : ''}>Next</button>
      <button class="pagination-btn" onclick="setLeaderPage('${kind}', ${pages})" ${page >= pages ? 'disabled' : ''}>Last</button>
    </div>`;
}

