// ── TEAM RANKINGS PAGE ─────────────────────────────────────────────────────────
let rankingsSort = { col: 'score', asc: false };

function clamp(n, lo = 0, hi = 100) {
  return Math.max(lo, Math.min(hi, n));
}

function avgNums(vals) {
  const nums = vals.filter(v => Number.isFinite(v));
  return nums.length ? nums.reduce((s, v) => s + v, 0) / nums.length : 0;
}

function fmtSigned(v, digits = 1) {
  if (!Number.isFinite(v)) return '—';
  return `${v > 0 ? '+' : ''}${v.toFixed(digits)}`;
}

function teamSearchKey(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/&/g, 'and')
    .replace(/[^a-z0-9 ]+/g, ' ')
    .replace(/\b(high|school|baseball|prep|preparatory|academy|regional|the)\b/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function matchOpponentTeam(opponent) {
  const oppKey = teamSearchKey(opponent);
  if (!oppKey) return null;
  if (!TEAM_MATCH_LIST) {
    TEAM_MATCH_LIST = Object.keys(TM)
      .map(team => ({ team, key: teamSearchKey(team) }))
      .filter(x => x.key)
      .sort((a, b) => b.key.length - a.key.length);
  }
  for (const { team, key } of TEAM_MATCH_LIST) {
    if (!key) continue;
    if (oppKey === key || oppKey.startsWith(`${key} `) || key.startsWith(`${oppKey} `) || oppKey.includes(` ${key} `)) {
      return team;
    }
  }
  return null;
}

function percentileFromRows(rows, key, value, lowerBetter = false, predicate = null) {
  if (!Number.isFinite(value)) return 50;
  const vals = rows
    .filter(r => !predicate || predicate(r))
    .map(r => r[key])
    .filter(v => Number.isFinite(v));
  return vals.length ? calcPct(vals, value, lowerBetter) : 50;
}

function dampenRunMargin(rs, ra) {
  const margin = rs - ra;
  const absMargin = Math.abs(margin);
  if (absMargin <= 6) return { ratingRs: rs, ratingRa: ra, dampedMargin: margin, blowoutRuns: 0 };

  const dampedAbs = 6 + Math.sqrt(absMargin - 6) * 1.25;
  const dampedMargin = Math.sign(margin) * dampedAbs;
  const ratingRs = margin > 0 ? ra + dampedAbs : rs;
  const ratingRa = margin > 0 ? ra : rs + dampedAbs;

  return {
    ratingRs,
    ratingRa,
    dampedMargin,
    blowoutRuns: absMargin - dampedAbs,
  };
}

function buildTeamPowerRaw() {
  return Object.keys(TM).map(team => {
    const standing = teamStandingsRow(team);
    const tp = AP.filter(p => p.team === team);
    const pitchers = PP.filter(p => p.team === team);

    const teamPA = tp.reduce((s, p) => s + p.PA, 0);
    const wavg = k => teamPA ? tp.reduce((s, p) => s + (p[k] || 0) * p.PA, 0) / teamPA : 0;
    const wOBA = teamPA > 0
      ? (0.7 * tp.reduce((s, p) => s + p.BB + p.HBP, 0) +
         0.9 * tp.reduce((s, p) => s + p.B1, 0) +
         1.3 * tp.reduce((s, p) => s + p.B2, 0) +
         1.6 * tp.reduce((s, p) => s + p.B3, 0) +
         2.0 * tp.reduce((s, p) => s + p.HR, 0)) / teamPA
      : 0;
    const wRC_plus = Math.round(((wOBA - 0.353) / 1.12 + 0.177) / 0.177 * 100);

    const IP = pitchers.reduce((s, p) => s + p.IP, 0);
    const ER = pitchers.reduce((s, p) => s + p.ER, 0);
    const BB = pitchers.reduce((s, p) => s + p.BB, 0);
    const H = pitchers.reduce((s, p) => s + p.H, 0);
    const K = pitchers.reduce((s, p) => s + p.K, 0);
    const HB = pitchers.reduce((s, p) => s + (p.HB || p.HBP || 0), 0);
    const ERA = IP > 0 ? (ER / IP) * 7 : 0;
    const WHIP = IP > 0 ? (BB + H) / IP : 0;
    const FIP = IP > 0 ? ((3 * (BB + HB) - 2 * K) / IP) + 3.10 : 0;
    const K7 = IP > 0 ? (K / IP) * 7 : 0;

    const sched = (typeof SCHEDULES !== 'undefined' && SCHEDULES[team]) || {};
    const completedGames = (sched.games || []).filter(g => g.score && (g.outcome === 'W' || g.outcome === 'L'));
    const gameResults = [];
    const last5 = completedGames.slice(-5);
    let last5RS = 0, last5RA = 0, last5W = 0;
    completedGames.forEach(g => {
      const parts = g.score.split('-').map(Number);
      if (parts.length !== 2 || Number.isNaN(parts[0]) || Number.isNaN(parts[1])) return;
      const opponent = matchOpponentTeam(g.opponent);
      const rs = g.outcome === 'W' ? parts[0] : parts[1];
      const ra = g.outcome === 'W' ? parts[1] : parts[0];
      const dampened = dampenRunMargin(rs, ra);
      gameResults.push({ opponent, rs, ra, ...dampened });
    });
    last5.forEach(g => {
      const parts = g.score.split('-').map(Number);
      if (parts.length !== 2 || Number.isNaN(parts[0]) || Number.isNaN(parts[1])) return;
      if (g.outcome === 'W') { last5RS += parts[0]; last5RA += parts[1]; last5W++; }
      else { last5RS += parts[1]; last5RA += parts[0]; }
    });

    return {
      team,
      m: TM[team],
      conf: TM[team]?.div || '',
      W: standing.W,
      L: standing.L,
      G: standing.G,
      wpct: standing.wpct,
      RS: standing.RS,
      RA: standing.RA,
      rdiff: standing.rdiff,
      rdiffPG: standing.G > 0 ? standing.rdiff / standing.G : 0,
      rsPG: standing.rsPG,
      raPG: standing.raPG,
      pythWpct: standing.pythWpct,
      teamPA,
      wOBA,
      OPS: wavg('OPS'),
      wRC_plus,
      IP,
      ERA,
      FIP,
      WHIP,
      K7,
      last5G: last5.length,
      last5W,
      last5Pct: last5.length ? last5W / last5.length : 0.5,
      last5RDiffPG: last5.length ? (last5RS - last5RA) / last5.length : 0,
      opponents: gameResults.map(g => g.opponent).filter(Boolean),
      gameResults,
      blowoutMargin: gameResults.length ? avgNums(gameResults.map(g => g.blowoutRuns)) : 0,
    };
  });
}

function calculateTeamPowerRatings() {
  const rows = buildTeamPowerRaw();
  const rowByTeam = Object.fromEntries(rows.map(r => [r.team, r]));
  const allGameResults = rows.flatMap(r => r.gameResults);
  const leagueRPG = allGameResults.length
    ? allGameResults.reduce((s, g) => s + g.ratingRs, 0) / allGameResults.length
    : 5;
  const EXP = 1.83;
  const pyth = (off, def) => {
    const o = Math.max(0.1, off);
    const d = Math.max(0.1, def);
    return Math.pow(o, EXP) / (Math.pow(o, EXP) + Math.pow(d, EXP));
  };

  rows.forEach(r => {
    const hasGames = r.G > 0;
    const hasHit = r.teamPA > 0;
    const hasPit = r.IP > 0;
    const runBase = hasGames ? (
      percentileFromRows(rows, 'rdiffPG', r.rdiffPG, false, x => x.G > 0) * 0.45 +
      percentileFromRows(rows, 'pythWpct', r.pythWpct, false, x => x.G > 0) * 0.35 +
      percentileFromRows(rows, 'wpct', r.wpct, false, x => x.G > 0) * 0.20
    ) : 50;
    const offense = hasHit ? (
      percentileFromRows(rows, 'wRC_plus', r.wRC_plus, false, x => x.teamPA > 0) * 0.40 +
      percentileFromRows(rows, 'wOBA', r.wOBA, false, x => x.teamPA > 0) * 0.25 +
      percentileFromRows(rows, 'OPS', r.OPS, false, x => x.teamPA > 0) * 0.20 +
      percentileFromRows(rows, 'rsPG', r.rsPG, false, x => x.G > 0) * 0.15
    ) : 50;
    const pitching = hasPit ? (
      percentileFromRows(rows, 'ERA', r.ERA, true, x => x.IP > 0) * 0.30 +
      percentileFromRows(rows, 'WHIP', r.WHIP, true, x => x.IP > 0) * 0.20 +
      percentileFromRows(rows, 'FIP', r.FIP, true, x => x.IP > 0) * 0.20 +
      percentileFromRows(rows, 'K7', r.K7, false, x => x.IP > 0) * 0.15 +
      percentileFromRows(rows, 'raPG', r.raPG, true, x => x.G > 0) * 0.15
    ) : 50;
    const recent = r.last5G ? (
      percentileFromRows(rows, 'last5Pct', r.last5Pct, false, x => x.last5G > 0) * 0.55 +
      percentileFromRows(rows, 'last5RDiffPG', r.last5RDiffPG, false, x => x.last5G > 0) * 0.45
    ) : 50;

    r.runBase = runBase;
    r.offense = offense;
    r.pitching = pitching;
    r.recent = recent;
    r.baseRating = clamp(runBase * 0.45 + offense * 0.25 + pitching * 0.20 + recent * 0.10);
    r.adjO = hasGames ? r.rsPG : leagueRPG;
    r.adjD = hasGames ? r.raPG : leagueRPG;
  });

  // KenPom-style adjusted efficiency loop for baseball:
  // AdjO = runs scored per game adjusted for opponent defense.
  // AdjD = runs allowed per game adjusted for opponent offense.
  // Both are normalized to an average opponent on a neutral field.
  for (let iter = 0; iter < 14; iter++) {
    const next = {};
    rows.forEach(r => {
      if (!r.gameResults.length) {
        next[r.team] = { adjO: r.adjO, adjD: r.adjD };
        return;
      }
      let weightTotal = 0;
      let offTotal = 0;
      let defTotal = 0;
      r.gameResults.forEach((g, i) => {
        const opp = rowByTeam[g.opponent] || { adjO: leagueRPG, adjD: leagueRPG };
        const recentWeight = 1 + (i / Math.max(1, r.gameResults.length - 1)) * 0.12;
        offTotal += (g.ratingRs * leagueRPG / Math.max(1, opp.adjD)) * recentWeight;
        defTotal += (g.ratingRa * leagueRPG / Math.max(1, opp.adjO)) * recentWeight;
        weightTotal += recentWeight;
      });
      next[r.team] = {
        adjO: offTotal / weightTotal,
        adjD: defTotal / weightTotal,
      };
    });
    rows.forEach(r => {
      r.adjO = next[r.team].adjO;
      r.adjD = next[r.team].adjD;
    });
  }

  rows.forEach(r => {
    const oppRows = r.opponents.map(t => rowByTeam[t]).filter(Boolean);
    r.oppAdjO = oppRows.length ? avgNums(oppRows.map(o => o.adjO)) : leagueRPG;
    r.oppAdjD = oppRows.length ? avgNums(oppRows.map(o => o.adjD)) : leagueRPG;
    r.sosPyth = pyth(r.oppAdjO, r.oppAdjD);
    r.sos = r.sosPyth * 100;
    r.sosComp = percentileFromRows(rows, 'sos', r.sos, false);
    r.adjRDiffPG = r.adjO - r.adjD;
    r.adjRun = r.G > 0 ? percentileFromRows(rows, 'adjRDiffPG', r.adjRDiffPG, false, x => x.G > 0) : 50;
    r.pywp = pyth(r.adjO, r.adjD);
    r.luck = r.wpct - r.pywp;
    r.score = clamp(r.pywp * 100);
  });

  TEAM_POWER_RATINGS = rows.sort((a, b) => b.score - a.score || b.adjRDiffPG - a.adjRDiffPG);
  TEAM_POWER_RATINGS.forEach((r, i) => { r.rank = i + 1; });
  TEAM_POWER_BY_TEAM = Object.fromEntries(TEAM_POWER_RATINGS.map(r => [r.team, r]));
}

function renderTeamRankings() {
  if (!TEAM_POWER_RATINGS.length) calculateTeamPowerRatings();
  const selDivs = getSelectedDivs('rankDiv');
  const teams = TEAM_POWER_RATINGS.filter(t => !selDivs || selDivs.includes(t.conf));

  const cols = [
    { key:'score',      label:'DI Score', fmt:v=>v.toFixed(1), lowerBetter:false },
    { key:'adjO',       label:'AdjO',     fmt:v=>v.toFixed(2), lowerBetter:false },
    { key:'adjD',       label:'AdjD',     fmt:v=>v.toFixed(2), lowerBetter:true },
    { key:'sos',        label:'SOS',      fmt:v=>v.toFixed(1), lowerBetter:false },
    { key:'luck',       label:'Luck',     fmt:v=>fmtSigned(v, 3).replace(/^([-+])0/, '$1'), lowerBetter:true },
    { key:'blowoutMargin', label:'BLOW',  fmt:v=>v.toFixed(2), lowerBetter:true },
    { key:'wpct',       label:'PCT',      fmt:v=>v.toFixed(3).replace(/^0/,''), lowerBetter:false },
    { key:'rsPG',       label:'RS/G',     fmt:v=>v.toFixed(2), lowerBetter:false },
    { key:'raPG',       label:'RA/G',     fmt:v=>v.toFixed(2), lowerBetter:true },
  ];
  if (!cols.find(c => c.key === rankingsSort.col)) rankingsSort = { col:'score', asc:false };

  const sorted = [...teams].sort((a, b) => {
    const av = a[rankingsSort.col];
    const bv = b[rankingsSort.col];
    if (av === bv) return b.score - a.score;
    return rankingsSort.asc ? av - bv : bv - av;
  });

  const sortArrow = rankingsSort.asc ? ' ▴' : ' ▾';

  document.getElementById('rankingsHead').innerHTML = `<tr>
    <th style="width:28px">#</th>
    <th>Team</th>
    <th>Conf</th>
    <th class="num">Record</th>
    ${cols.map(c => `<th class="num${c.key===rankingsSort.col?' rankings-sort-active':''}" style="cursor:pointer" onclick="sortRankings('${c.key}',${c.lowerBetter})">${c.label}${c.key===rankingsSort.col?sortArrow:''}</th>`).join('')}
  </tr>`;

  document.getElementById('rankingsBody').innerHTML = sorted.map((t,i) => `
    <tr onclick="showTeam(decodeURIComponent('${encodeURIComponent(t.team)}'),'team-rankings')">
      <td style="font-family:'Outfit',sans-serif;font-weight:700;color:${t.rank<=3?'var(--accent)':'var(--muted)'}">${t.rank}</td>
      <td>
        <div style="display:flex;align-items:center;gap:8px">
          ${t.m?.logo ? `<img src="${t.m.logo}" width="22" height="22" style="object-fit:contain;border-radius:2px">` : ''}
          <span style="font-family:'Outfit',sans-serif;font-weight:600;color:${t.m?.t||'var(--text)'}">${t.team}</span>
          <span style="font-size:11px;color:var(--muted)">${t.m?.mascot||''}</span>
        </div>
      </td>
      <td style="font-size:11px;color:var(--muted2);max-width:170px">${t.conf}</td>
      <td class="num"><span class="standings-record ${t.wpct > 0.5 ? 'over-500' : t.wpct < 0.5 ? 'under-500' : 'even-500'}">${t.W}-${t.L}</span></td>
      ${cols.map(c => {
        const v = t[c.key];
        const isSort = c.key === rankingsSort.col;
        return `<td class="num" style="${isSort?'font-weight:700;color:var(--accent)':''}">${Number.isFinite(v)?c.fmt(v):'—'}</td>`;
      }).join('')}
    </tr>`).join('');
}

function sortRankings(col, lowerBetter) {
  if (rankingsSort.col === col) {
    rankingsSort.asc = !rankingsSort.asc;
  } else {
    rankingsSort = { col, asc: lowerBetter };
  }
  renderTeamRankings();
}

function teamLogoImg(team, cls = '') {
  const m = TM[team] || {};
  return m.logo ? `<img class="${cls}" src="${m.logo}" alt="" aria-hidden="true">` : '';
}

function leagueRunEnvironment() {
  if (!TEAM_POWER_RATINGS.length) calculateTeamPowerRatings();
  const rows = TEAM_POWER_RATINGS.filter(t => t.G > 0 && Number.isFinite(t.adjO));
  return rows.length ? avgNums(rows.map(t => t.adjO)) : 5;
}

function getPredictorTeamValue(side) {
  const raw = document.getElementById('predictTeam' + side)?.value?.trim() || '';
  if (TM[raw]) return raw;
  const lower = raw.toLowerCase();
  return Object.keys(TM).find(t => t.toLowerCase() === lower) || raw;
}

function pitcherKey(p) {
  return `${p.name}||${p.team}`;
}

function pitcherRunEstimate(p) {
  if (!p || !Number.isFinite(p.IP) || p.IP <= 0) return null;
  const era = Number.isFinite(p.ERA) ? p.ERA : null;
  const fip = Number.isFinite(p.FIP) ? p.FIP : null;
  if (era === null && fip === null) return null;
  const estimate = era !== null && fip !== null ? (era * 0.4 + fip * 0.6) : (era ?? fip);
  return clamp(estimate, 0.5, 12);
}

function effectiveDefenseWithStarter(teamRow, pitcherId) {
  if (!pitcherId) return teamRow.adjD;
  const starterKey = decodeURIComponent(pitcherId);
  const starter = PP.find(p => pitcherKey(p) === starterKey);
  const starterRA = pitcherRunEstimate(starter);
  if (!starter || starterRA === null) return teamRow.adjD;
  const reliability = clamp(starter.IP / 25, 0, 1);
  const starterShare = 0.68 * reliability;
  return (starterRA * starterShare) + (teamRow.adjD * (1 - starterShare));
}

function updatePredictorPitchers(side) {
  const team = getPredictorTeamValue(side);
  const sel = document.getElementById('predictPitcher' + side);
  if (!sel) return;
  const previous = sel.value;
  const pitchers = PP
    .filter(p => p.team === team && p.IP > 0)
    .sort((a, b) => b.IP - a.IP || a.ERA - b.ERA);
  sel.innerHTML = `<option value="">Team pitching staff</option>` + pitchers.map(p =>
    `<option value="${encodeURIComponent(pitcherKey(p))}">${p.name} · ${p.IP.toFixed(1)} IP · ${p.ERA.toFixed(2)} ERA · ${p.FIP.toFixed(2)} FIP</option>`
  ).join('');
  if ([...sel.options].some(o => o.value === previous)) sel.value = previous;
}

function handlePredictorTeamChange(side) {
  updatePredictorPitchers(side);
  renderMatchupPrediction();
}

function predictMatchup(teamA, teamB, venue = 'neutral', pitcherA = '', pitcherB = '') {
  if (!TEAM_POWER_RATINGS.length) calculateTeamPowerRatings();
  const a = TEAM_POWER_BY_TEAM[teamA];
  const b = TEAM_POWER_BY_TEAM[teamB];
  if (!a || !b || teamA === teamB) return null;

  const leagueRPG = leagueRunEnvironment();
  const homeRuns = 0.25;
  const aHome = venue === 'a-home' ? homeRuns : 0;
  const bHome = venue === 'b-home' ? homeRuns : 0;
  const aDefense = effectiveDefenseWithStarter(a, pitcherA);
  const bDefense = effectiveDefenseWithStarter(b, pitcherB);
  const expA = Math.max(0.1, (a.adjO * bDefense / Math.max(0.1, leagueRPG)) + aHome);
  const expB = Math.max(0.1, (b.adjO * aDefense / Math.max(0.1, leagueRPG)) + bHome);
  const EXP = 1.83;
  const winProbA = Math.pow(expA, EXP) / (Math.pow(expA, EXP) + Math.pow(expB, EXP));
  const winner = winProbA >= 0.5 ? teamA : teamB;
  const winnerProb = winProbA >= 0.5 ? winProbA : 1 - winProbA;
  return { a, b, teamA, teamB, expA, expB, winProbA, winner, winnerProb, aDefense, bDefense };
}

function renderMatchupPrediction() {
  const teamA = getPredictorTeamValue('A');
  const teamB = getPredictorTeamValue('B');
  const venueSel = document.getElementById('predictVenue');
  const pitcherA = document.getElementById('predictPitcherA')?.value || '';
  const pitcherB = document.getElementById('predictPitcherB')?.value || '';
  const el = document.getElementById('matchupPrediction');
  if (!el) return;
  const result = predictMatchup(teamA, teamB, venueSel?.value || 'neutral', pitcherA, pitcherB);
  if (!result) {
    el.innerHTML = `<div class="predictor-empty">Search and choose two different teams to generate a prediction.</div>`;
    return;
  }
  const { a, b, expA, expB, winProbA, winner, winnerProb, aDefense, bDefense } = result;
  const aPct = Math.round(winProbA * 100);
  const bPct = 100 - aPct;
  const confidence = winnerProb >= 0.75 ? 'Strong edge' : winnerProb >= 0.62 ? 'Clear edge' : 'Toss-up range';
  const winnerScore = winner === teamA ? expA : expB;
  const loserScore = winner === teamA ? expB : expA;
  const venueText = venueSel?.selectedOptions?.[0]?.textContent || 'Neutral';
  const starterA = pitcherA ? PP.find(p => pitcherKey(p) === decodeURIComponent(pitcherA)) : null;
  const starterB = pitcherB ? PP.find(p => pitcherKey(p) === decodeURIComponent(pitcherB)) : null;
  const starterText = [starterA ? `${teamA}: ${starterA.name}` : '', starterB ? `${teamB}: ${starterB.name}` : ''].filter(Boolean).join(' · ');

  el.innerHTML = `
    <div class="prediction-card">
      <div class="prediction-head">
        <div class="prediction-team">
          ${teamLogoImg(teamA, 'prediction-logo')}
          <div>
            <div class="prediction-team-name">${teamA}</div>
            <div class="prediction-team-meta">#${a.rank} · DI ${a.score.toFixed(1)} · ${a.W}-${a.L}</div>
          </div>
        </div>
        <div class="prediction-vs">vs</div>
        <div class="prediction-team prediction-team-right">
          ${teamLogoImg(teamB, 'prediction-logo')}
          <div>
            <div class="prediction-team-name">${teamB}</div>
            <div class="prediction-team-meta">#${b.rank} · DI ${b.score.toFixed(1)} · ${b.W}-${b.L}</div>
          </div>
        </div>
      </div>

      <div class="prediction-main">
        <div class="prediction-pick-label">Projected Winner</div>
        <div class="prediction-pick">${winner}</div>
        <div class="prediction-score">${winnerScore.toFixed(1)}-${loserScore.toFixed(1)}</div>
        <div class="prediction-confidence">${confidence} · ${(winnerProb * 100).toFixed(1)}% win probability · ${venueText}</div>
        ${starterText ? `<div class="prediction-starters">${starterText}</div>` : ''}
      </div>

      <div class="prediction-prob">
        <div class="prediction-prob-row">
          <span>${teamA}</span><strong>${aPct}%</strong>
        </div>
        <div class="prediction-bar">
          <div class="prediction-bar-a" style="width:${aPct}%"></div>
          <div class="prediction-bar-b" style="width:${bPct}%"></div>
        </div>
        <div class="prediction-prob-row">
          <span>${teamB}</span><strong>${bPct}%</strong>
        </div>
      </div>

      <div class="prediction-metrics">
        ${predictionMetric('AdjO', a.adjO.toFixed(2), b.adjO.toFixed(2))}
        ${predictionMetric('Game AdjD', aDefense.toFixed(2), bDefense.toFixed(2))}
        ${predictionMetric('SOS', a.sos.toFixed(1), b.sos.toFixed(1))}
        ${predictionMetric('Expected Runs', expA.toFixed(1), expB.toFixed(1))}
      </div>
    </div>
  `;
}

function predictionMetric(label, aVal, bVal) {
  return `<div class="prediction-metric">
    <div class="prediction-metric-label">${label}</div>
    <div class="prediction-metric-values"><span>${aVal}</span><span>${bVal}</span></div>
  </div>`;
}

function swapPredictorTeams() {
  const aSel = document.getElementById('predictTeamA');
  const bSel = document.getElementById('predictTeamB');
  const aPit = document.getElementById('predictPitcherA');
  const bPit = document.getElementById('predictPitcherB');
  if (!aSel || !bSel) return;
  const a = aSel.value;
  const pitA = aPit?.value || '';
  const pitB = bPit?.value || '';
  aSel.value = bSel.value;
  bSel.value = a;
  updatePredictorPitchers('A');
  updatePredictorPitchers('B');
  if (aPit && bPit) {
    aPit.value = pitB;
    bPit.value = pitA;
  }
  renderMatchupPrediction();
}

// ── STANDINGS ─────────────────────────────────────────────────────────────────
function teamStandingsRow(team) {
  const sched    = (typeof SCHEDULES !== 'undefined' && SCHEDULES[team]) || {};
  const games    = sched.games || [];
  const W        = sched.wins   || 0;
  const L        = sched.losses || 0;
  const G        = W + L;

  // Runs scored / allowed from game scores
  let RS = 0, RA = 0;
  games.forEach(g => {
    if (g.score && g.outcome) {
      const parts = g.score.split('-').map(Number);
      if (parts.length === 2 && !isNaN(parts[0]) && !isNaN(parts[1])) {
        // nj.com shows winning score first — so W = parts[0] is team, L = parts[0] is opponent
        if (g.outcome === 'W') { RS += parts[0]; RA += parts[1]; }
        else                   { RS += parts[1]; RA += parts[0]; }
      }
    }
  });

  const wpct  = G > 0 ? W / G : 0;
  const rdiff = RS - RA;
  const raPG  = G > 0 ? RA / G : 0;
  const rsPG  = G > 0 ? RS / G : 0;

  // Pythagorean expected record (exponent 1.83)
  const EXP = 1.83;
  const pythWpct = (RS + RA) > 0
    ? Math.pow(RS, EXP) / (Math.pow(RS, EXP) + Math.pow(RA, EXP))
    : 0.5;
  const pythW = Math.round(pythWpct * G);
  const pythL = G - pythW;

  return { team, W, L, G, wpct, RS, RA, rdiff, raPG, rsPG,
           pythW, pythL, pythWpct };
}

function renderStandings() {
  const confFilter = document.getElementById('standingsConfFilter')?.value?.toLowerCase() || '';
  const ALL_CONFS  = [...new Set(Object.values(TM).map(m => m.div).filter(Boolean))].sort();
  const DIVISIONS  = confFilter
    ? ALL_CONFS.filter(c => c.toLowerCase().includes(confFilter))
    : ALL_CONFS;

  const el = document.getElementById('standingsContent');
  if (!el) return;

  // Show last updated
  const upd = document.getElementById('standingsUpdated');
  if (upd && typeof DATA_UPDATED !== 'undefined') upd.textContent = `Updated ${DATA_UPDATED}`;

  el.innerHTML = DIVISIONS.map(div => {
    const divTeams = Object.keys(TM).filter(t => TM[t].div === div);
    const rows = divTeams.map(t => teamStandingsRow(t))
                         .sort((a, b) => b.wpct - a.wpct || b.rdiff - a.rdiff);

    const tableRows = rows.map((r, i) => {
      const m        = TM[r.team] || {};
      const wlClass  = r.wpct > 0.5 ? 'over-500' : r.wpct < 0.5 ? 'under-500' : 'even-500';
      const pdiff    = r.pythW - r.W;
      const pdiffStr = pdiff > 0 ? `+${pdiff}` : `${pdiff}`;
      const pdiffCls = pdiff > 0 ? 'pyth-diff-pos' : pdiff < 0 ? 'pyth-diff-neg' : 'pyth-diff-neu';

      return `<tr onclick="showTeam('${r.team}','standings')">
        <td>
          <div class="standings-team-cell">
            <span class="standings-pos ${i === 0 ? 'leader' : ''}">${i + 1}</span>
            ${m.logo ? `<img src="${m.logo}" width="22" height="22" style="object-fit:contain;border-radius:2px;flex-shrink:0">` : ''}
            <span class="standings-team-name" style="color:${m.t || 'var(--text)'}">${r.team}</span>
          </div>
        </td>
        <td class="num">
          <span class="standings-record ${wlClass}">${r.W}-${r.L}</span>
        </td>
        <td class="num" style="font-variant-numeric:tabular-nums">${r.wpct.toFixed(3).replace(/^0/,'')}</td>
        <td class="num" style="color:${r.rdiff > 0 ? '#4ade80' : r.rdiff < 0 ? '#f87171' : 'var(--muted2)'}">
          ${r.rdiff > 0 ? '+' : ''}${r.rdiff}
        </td>
        <td class="num" style="color:var(--muted2)">${r.rsPG.toFixed(2)}</td>
        <td class="num" style="color:var(--muted2)">${r.raPG.toFixed(2)}</td>
        <td class="num">
          <span style="font-family:'Bebas Neue',sans-serif;font-size:14px">${r.pythW}-${r.pythL}</span>
          <span class="${pdiffCls}" style="margin-left:5px">(${pdiffStr})</span>
        </td>
      </tr>`;
    }).join('');

    return `<div class="standings-division">
      <div class="standings-division-header">
        <span class="standings-division-name">${div}</span>
        <span class="standings-division-sub">${rows.length} teams</span>
      </div>
      <table class="standings-table">
        <thead><tr>
          <th>Team</th>
          <th class="num">Record</th>
          <th class="num" title="Win Percentage">PCT</th>
          <th class="num" title="Run Differential">RDIFF</th>
          <th class="num" title="Runs Scored per Game">RS/G</th>
          <th class="num" title="Runs Allowed per Game">RA/G</th>
          <th class="num" title="Pythagorean Expected Record (RS^1.83 / (RS^1.83 + RA^1.83)) — difference from actual in parentheses">PYTH</th>
        </tr></thead>
        <tbody>${tableRows}</tbody>
      </table>
    </div>`;
  }).join('');
}

